## Deobfuscated Code

```javascript
// Constants
var TAU = 6.283;          // ~2π
var PHI = 1.618;          // Golden ratio
var SQRT1_2 = 0.707;      // ~√(1/2)

// Physics configuration
var config = {
  repulsionStrength: 4000,
  frictionCoeff: 0.004,
  amplitudeDamping: 0.92,
  dispersal: 0.0003,
  streamMax: 40,
  viscosity: 0.04,
  easing: 0.06
};

// Nodes (graph vertices)
var nodes = [
  { id: "hub",     label: "Hub",     r: 26, x: 400, y: 300, vx: 0, vy: 0 },
  { id: "alpha",   label: "Alpha",   r: 16, x: 500, y: 200, vx: 0, vy: 0 },
  { id: "beta",    label: "Beta",    r: 16, x: 300, y: 400, vx: 0, vy: 0 },
  { id: "gamma",   label: "Gamma",   r: 14, x: 250, y: 180, vx: 0, vy: 0 },
  { id: "delta",   label: "Delta",   r: 14, x: 550, y: 380, vx: 0, vy: 0 },
  { id: "epsilon", label: "Epsilon", r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

// Edges (spring connections between nodes)
var edges = [
  { a: "hub", b: "alpha",   rest: 160, k: 0.006 },
  { a: "hub", b: "beta",    rest: 160, k: 0.005 },
  { a: "hub", b: "gamma",   rest: 170, k: 0.004 },
  { a: "hub", b: "delta",   rest: 170, k: 0.004 },
  { a: "hub", b: "epsilon", rest: 180, k: 0.003 },
  { a: "alpha", b: "beta",    rest: 200, k: 0.002 },
  { a: "gamma", b: "delta",   rest: 220, k: 0.002 },
  { a: "alpha", b: "epsilon", rest: 200, k: 0.002 }
];

// Camera / viewport state
var camera = { x: 400, y: 300, zoom: 1 };
var cameraTarget = { x: 400, y: 300, zoom: 1 };

// Particle stream
var particles = [];
var frameCount = 0;

// Find a node by ID
function findNode(id) {
  for (var i = 0; i < nodes.length; i++) {
    if (nodes[i].id === id) return nodes[i];
  }
  return null;
}

// Apply physics forces to all nodes
function applyForces() {
  // 1. Node-to-node REPULSION (Coulomb-like)
  for (var i = 0; i < nodes.length; i++) {
    for (var j = i + 1; j < nodes.length; j++) {
      var dx = nodes[i].x - nodes[j].x;
      var dy = nodes[i].y - nodes[j].y;
      var dist = Math.sqrt(dx * dx + dy * dy) || 1;
      var force = config.repulsionStrength / (dist * dist);
      var fx = (dx / dist) * force;
      var fy = (dy / dist) * force;

      nodes[i].vx += fx;
      nodes[i].vy += fy;
      nodes[j].vx -= fx;
      nodes[j].vy -= fy;
    }
  }

  // 2. Edge SPRING forces (Hooke's law)
  for (var e = 0; e < edges.length; e++) {
    var nodeA = findNode(edges[e].a);
    var nodeB = findNode(edges[e].b);
    if (!nodeA || !nodeB) continue;

    var dx = nodeB.x - nodeA.x;
    var dy = nodeB.y - nodeA.y;
    var dist = Math.sqrt(dx * dx + dy * dy) || 1;
    var displacement = dist - edges[e].rest;
    var force = (edges[e].k || config.frictionCoeff) * displacement;

    nodeA.vx += (dx / dist) * force;
    nodeA.vy += (dy / dist) * force;
    nodeB.vx -= (dx / dist) * force;
    nodeB.vy -= (dy / dist) * force;
  }

  // 3. Center GRAVITY + velocity DAMPING + position update
  for (var n = 0; n < nodes.length; n++) {
    nodes[n].vx += (400 - nodes[n].x) * config.dispersal;
    nodes[n].vy += (300 - nodes[n].y) * config.dispersal;
    nodes[n].vx *= config.amplitudeDamping;
    nodes[n].vy *= config.amplitudeDamping;
    nodes[n].x += nodes[n].vx;
    nodes[n].y += nodes[n].vy;
  }
}

// Spawn new particles from random nodes
function spawnParticles() {
  if (particles.length >= config.streamMax) return;

  var sourceNode = nodes[Math.floor(Math.random() * nodes.length)];
  var angle = Math.random() * TAU;
  var speed = 0.3 + Math.random() * SQRT1_2;

  particles.push({
    x: sourceNode.x,
    y: sourceNode.y,
    vx: Math.cos(angle) * speed,
    vy: Math.sin(angle) * speed,
    age: 0,
    maxAge: 800 + Math.random() * 1200,
    size: 0.8 + Math.random() * PHI * SQRT1_2
  });
}

// Update existing particles
function updateParticles() {
  for (var i = particles.length - 1; i >= 0; i--) {
    var p = particles[i];
    p.vx *= 1 - config.viscosity * 0.125;
    p.vy *= 1 - config.viscosity * 0.125;
    p.x += p.vx;
    p.y += p.vy;
    p.age++;
    if (p.age > p.maxAge) particles.splice(i, 1);
  }
}

// Smooth camera easing
function updateCamera() {
  camera.x += (cameraTarget.x - camera.x) * config.easing;
  camera.y += (cameraTarget.y - camera.y) * config.easing;
  camera.zoom += (cameraTarget.zoom - camera.zoom) * config.easing;
}

// Main loop
function tick() {
  applyForces();
  frameCount++;
  updateParticles();
  if (frameCount % 3 === 0) spawnParticles();
  updateCamera();
}

setInterval(tick, 16); // ~60 FPS
```

## What It Does

This is a **force-directed graph layout simulation** with particle effects. Specifically:

### 🔵 Force-Directed Graph
- **6 nodes** (Hub, Alpha, Beta, Gamma, Delta, Epsilon) connected by **8 spring edges** form a network graph
- **Three forces** act on every node each frame:
  1. **Repulsion** — all nodes push each other apart (inverse-square law, like electric charges)
  2. **Spring attraction** — connected nodes are pulled toward their rest-length distance (Hooke's law)
  3. **Center gravity** — all nodes are gently pulled toward the center point (400, 300) to prevent drifting away
- Velocities are **damped** by 0.92× each frame to prevent runaway oscillation

### ✨ Particle System
- Every 3 frames, a new **particle** spawns from a random node
- Particles drift outward in a random direction with slight viscous drag
- They have a limited lifespan (800–2000 frames) and are removed when expired
- Max 40 particles at once — creates a "streaming aura" visual effect

### 📷 Smooth Camera
- A camera position/zoom smoothly eases toward a target using linear interpolation (lerp with factor 0.06)

### ⏱️ Main Loop
Runs at **~60 FPS** (`setInterval` with 16ms), calling forces → particles → camera each tick.

> **In summary:** This is the physics engine/backend for an animated, interactive node-graph visualization — like a mini version of what you'd see in D3.js force layouts, with decorative particle streams emanating from nodes.
